export const code = async (inputs) => {
  // Test-only flow: scale matching + grade transfer, no OneDrive/AI.
  // inputs.country: Spanish-language country name (e.g. ALEMANIA)
  // inputs.grades: array of { subject, origin_grade } objects
  const BACKEND = 'http://backend:8000';
  const MIN_COVERAGE = 1.0;

  const grades = Array.isArray(inputs.grades) ? inputs.grades : [];
  const distinct = [...new Set(grades.map((g) => g.origin_grade).filter((v) => v != null))];

  // 1. Resolve the scale from country + observed grades (unauthenticated endpoint).
  const matchRes = await fetch(`${BACKEND}/scales/match`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ country: inputs.country || '', grades: distinct }),
  });
  const candidates = matchRes.ok ? await matchRes.json() : [];

  // 2. Decide confidence: best scale must fully cover the grades and not tie another.
  const top = candidates[0];
  const second = candidates[1];
  let reason = null;
  if (!top || top.coverage < MIN_COVERAGE) {
    reason = top ? 'low_coverage' : 'no_candidates';
  } else if (
    second &&
    second.coverage === top.coverage &&
    second.scale_total_grades === top.scale_total_grades
  ) {
    reason = 'ambiguous';
  }

  // 3a. Unresolved/ambiguous -> report needs-review instead of guessing.
  if (reason) {
    return {
      status: 422,
      body: {
        status: 'NEEDS_REVIEW',
        reason,
        country: inputs.country || null,
        candidates: candidates.slice(0, 5),
      },
    };
  }

  // 3b. Confident -> transfer only the grades the matched scale actually covers.
  const unmatched = new Set(top.unmatched_grades || []);
  const coveredGrades = grades.filter((g) => !unmatched.has(g.origin_grade));

  const response = await fetch(`${BACKEND}/transfer/`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ scale_id: top.scale_id, grades: coveredGrades }),
  });

  const transfer = await response.json();

  return {
    status: response.status,
    body: {
      scale_id: top.scale_id,
      scale_description: top.scale_description,
      unmatched_grades: top.unmatched_grades || [],
      transfer,
    },
  };
};
